func Current() string {
	return Normalize(os.Getenv("MESHCLAW_LANG"))
}

func Normalize(value string) string {
	value = strings.ToLower(strings.TrimSpace(value))
	if value == "" {
		return Default
	}
	value = strings.ReplaceAll(value, "_", "-")
	if strings.HasPrefix(value, "ko") {
		return "ko"
	}
	if strings.HasPrefix(value, "en") {
		return "en"
	}
	return Default
}

func T(key string, args ...interface{}) string {
	return TF(Current(), key, args...)
}

func TF(locale, key string, args ...interface{}) string {
	locale = Normalize(locale)
	template := ""
	if pack, ok := packs[locale]; ok {
		template = pack[key]
	}
	if template == "" && locale != Default {
		template = packs[Default][key]
	}
	if template == "" {
		template = key
	}
	if len(args) == 0 {
		return template
	}
	return fmt.Sprintf(template, args...)
}
